package com.oneil.wellness.walkplanner.controller;
import com.oneil.wellness.walkplanner.activity.*;import java.util.*;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api") public class WalkController{
 private final WalkActivityService walks;private final OpportunityOutcomeService outcomes;public WalkController(WalkActivityService w,OpportunityOutcomeService o){walks=w;outcomes=o;}
 @PostMapping("/walks/start")@ResponseStatus(HttpStatus.CREATED)public WalkActivity start(@RequestBody WalkRequest r){return walks.start(r);}@PostMapping("/walks/{id}/complete")public WalkActivity complete(@PathVariable UUID id,@RequestBody(required=false)CompleteWalkRequest r){return walks.complete(id,r);}@PostMapping("/walks/{id}/cancel")@ResponseStatus(HttpStatus.NO_CONTENT)public void cancel(@PathVariable UUID id){walks.cancel(id);}@PostMapping("/walks/manual")@ResponseStatus(HttpStatus.CREATED)public WalkActivity manual(@RequestBody ManualWalkRequest r){return walks.manual(r);}@DeleteMapping("/walks/{id}")@ResponseStatus(HttpStatus.NO_CONTENT)public void delete(@PathVariable UUID id){walks.delete(id);}@GetMapping("/walks")public List<WalkActivity> list(){return walks.list();}@GetMapping("/walks/active")public ResponseEntity<WalkActivity> active(){return walks.active().map(ResponseEntity::ok).orElseGet(()->ResponseEntity.noContent().build());}
 @PostMapping("/opportunities/{id}/skip")public OpportunityOutcome skip(@PathVariable UUID id,@RequestParam(defaultValue="DASHBOARD")ActivitySource source){return outcomes.record(id,ActivityStatus.SKIPPED,source);}@PostMapping("/opportunities/{id}/dismiss")public OpportunityOutcome dismiss(@PathVariable UUID id,@RequestParam(defaultValue="DASHBOARD")ActivitySource source){return outcomes.record(id,ActivityStatus.DISMISSED,source);}@PostMapping("/opportunities/skip")public OpportunityOutcome skip(@RequestBody OpportunityActionRequest r){return outcomes.recordWindow(r.opportunityStart(),ActivityStatus.SKIPPED,r.source());}@PostMapping("/opportunities/dismiss")public OpportunityOutcome dismiss(@RequestBody OpportunityActionRequest r){return outcomes.recordWindow(r.opportunityStart(),ActivityStatus.DISMISSED,r.source());}
}
